    private void insertMenu(Long id, Long parentId, String appType, String type, String path,
                            String title, String icon, String permission, Integer sort, Boolean visible) {
        SysMenu existing = sysMenuMapper.selectById(id);
        SysMenu m = existing != null ? existing : new SysMenu();
        if (m.getId() == null) m.setId(id);
        m.setParentId(parentId);
        m.setAppType(appType);
        m.setType(type);
        m.setPath(path);
        m.setTitle(title != null ? title : (permission != null ? permission : type));
        m.setIcon(icon);
        m.setPermission(permission);
        m.setSort(sort);
        m.setVisible(visible);
        m.setStatus("ENABLE");
        m.setDeleted(false);
        if (m.getCreatedAt() == null) m.setCreatedAt(LocalDateTime.now());
        m.setUpdatedAt(LocalDateTime.now());
        if (existing == null) sysMenuMapper.insert(m); else sysMenuMapper.updateById(m);
    }

    private void initRoleMenus() {
        cleanupMerchantAgentRoleMenus();
        long rid = nextRoleMenuId();

        long[] adminMenuIds = {
            1000, 1001, 1100, 1101, 1102, 1103, 1104, 1105,
            1200, 1201, 1202, 1203, 1204,
            1300, 1301, 1302, 1303,
            1400, 1401, 1402, 1403, 1404, 1405, 1406,
            1500, 1501, 1502, 1503, 1504, 1505,
            1600, 1601, 1602, 1603,
            1700, 1701, 1702, 1703, 1704,
            1800, 1801, 1802,
            1850, 1851,
            2001, 2002, 2003, 2004,
            2011, 2012, 2013, 2014, 2015, 2016, 2017, 2018, 2019,
            2021, 2022, 2023, 2024,
            2031, 2032, 2033, 2034,
            2051, 2052, 2053,
            2061, 2062,
            2071, 2072, 2073,
            2081, 2082, 2083,
            2101, 2102, 2103,
            2111, 2112, 2121, 2131, 2141, 2142,
            2151, 2152, 2153,
            2161, 2162, 2163,
            2171, 2172, 2173,
            2181, 2182, 2183,
            2191, 2192, 2193,
            2201, 2202, 2203,
            2211, 2212, 2213,
            2221,
            2231, 2241, 2242, 2251, 2252, 2261, 2262, 2263,
            2301, 2302, 2303,
            2311, 2312
        };
        long[] adminExclude = {1104L, 1601L, 1602L, 2031L, 2032L, 2033L, 2034L, 2201L, 2202L, 2203L, 2211L, 2212L, 2213L};
        java.util.Set<Long> excludeSet = new java.util.HashSet<>();
        for (long e : adminExclude) excludeSet.add(e);

        for (long mid : adminMenuIds) {
            rid = insertRoleMenu(rid, 1L, mid);
        }
        for (long mid : adminMenuIds) {
            if (!excludeSet.contains(mid)) {
                rid = insertRoleMenu(rid, 2L, mid);
            }
        }

        long[] merchantMenuIds = {5000, 5001, 5100, 5101, 5102, 5103, 5200, 5201, 5300, 5301, 5302, 5303, 5304, 5305, 5306, 5500, 5501, 5502, 5503, 5600, 5601, 5602, 5603, 5700, 5701, 5750, 5751, 5801, 5802, 5811};
        for (long mid : merchantMenuIds) {
            rid = insertRoleMenu(rid, 3L, mid);
        }

        long[] agentMenuIds = {5300, 5301, 5302, 5303, 5304, 5400, 5401, 5402, 5403, 5602};
        for (long mid : agentMenuIds) {
            rid = insertRoleMenu(rid, 4L, mid);
        }
    }

    private void cleanupMerchantAgentRoleMenus() {
        sysRoleMenuMapper.delete(new LambdaQueryWrapper<SysRoleMenu>()
                .eq(SysRoleMenu::getRoleId, 3L)
                .in(SysRoleMenu::getMenuId, List.of(5400L, 5401L, 5402L, 5403L)));
    }


    private long nextRoleMenuId() {
        Long maxId = sysRoleMenuMapper.selectList(null).stream()
                .map(SysRoleMenu::getId)
                .filter(java.util.Objects::nonNull)
                .max(Long::compareTo)
                .orElse(2999L);
        return Math.max(maxId + 1, 3000L);
    }

    private long insertRoleMenu(long id, long roleId, long menuId) {
        Long cnt = sysRoleMenuMapper.selectCount(new LambdaQueryWrapper<SysRoleMenu>()
                .eq(SysRoleMenu::getRoleId, roleId)
                .eq(SysRoleMenu::getMenuId, menuId));
        if (cnt != null && cnt > 0) return id;
        SysRoleMenu rm = new SysRoleMenu();
        rm.setId(id);
        rm.setRoleId(roleId);
        rm.setMenuId(menuId);
        rm.setCreatedAt(LocalDateTime.now());
        sysRoleMenuMapper.insert(rm);
        return id + 1;
    }

